@Component("forwardFifo")
public class ForwardFifoStrategy implements SchedulingStrategy {
    @Override public String name() { return "FORWARD_FIFO"; }
    @Override public String description() { return "Forward scheduling with FIFO job ordering"; }

    @Override
    public ScheduleResult schedule(ScheduleRequest request) {
        // Sort jobs by arrival time (FIFO)
        List<ScheduleJob> sorted = new ArrayList<>(request.getJobs());
        sorted.sort(Comparator.comparing(j -> j.getArrivalTime() != null ? j.getArrivalTime() : request.getScheduleStart()));

        // Track resource availability: resourceId → earliest available time
        Map<Long, LocalDateTime> resourceAvailability = new HashMap<>();
        for (ResourceInfo res : request.getResources()) {
            resourceAvailability.put(res.getId(), request.getScheduleStart());
        }

        List<ScheduledOperation> operations = new ArrayList<>();
        List<ScheduleConflict> conflicts = new ArrayList<>();

        for (ScheduleJob job : sorted) {
            // Find matching resource (by type or specific ID)
            ResourceInfo selectedResource = findBestResource(job, request.getResources(), resourceAvailability);
            if (selectedResource == null) {
                conflicts.add(ScheduleConflict.builder().jobId(job.getId()).reason("No available resource of type " + job.getRequiredResourceType()).build());
                continue;
            }

            // Calculate start time (max of resource availability and job arrival)
            LocalDateTime startTime = resourceAvailability.get(selectedResource.getId());
            if (job.getArrivalTime() != null && job.getArrivalTime().isAfter(startTime)) {
                startTime = job.getArrivalTime();
            }

            // Add setup time if product change
            int setupTime = getSetupTime(request.getSetupTimes(), selectedResource.getId(), job.getProductId(), operations);
            startTime = startTime.plusMinutes(setupTime);

            LocalDateTime endTime = startTime.plusMinutes(job.getProcessingTimeMin());

            operations.add(ScheduledOperation.builder()
                .jobId(job.getId()).jobCode(job.getCode()).productName(job.getProductName())
                .operationName(job.getOperationName())
                .resourceId(selectedResource.getId()).resourceName(selectedResource.getName())
                .startTime(startTime).endTime(endTime)
                .setupTimeMin(setupTime).processingTimeMin(job.getProcessingTimeMin())
                .build());

            resourceAvailability.put(selectedResource.getId(), endTime);

            // Check due date
            if (job.getDueDate() != null && endTime.isAfter(job.getDueDate())) {
                conflicts.add(ScheduleConflict.builder()
                    .jobId(job.getId()).reason("Past due")
                    .requestedBy(job.getDueDate()).achievableBy(endTime).build());
            }
        }

        return ScheduleResult.builder()
            .strategy(name())
            .operations(operations)
            .conflicts(conflicts)
            .resourceUtilization(calculateUtilization(operations, request))
            .earliestCompletion(operations.stream().map(ScheduledOperation::getEndTime).max(LocalDateTime::compareTo).orElse(null))
            .build();
    }
}
```

Helper methods: findBestResource (match by type, pick earliest available), getSetupTime (lookup changeover), calculateUtilization.

