Create the APS scheduling orchestrator and REST endpoint.

Create:
1. platform/src/main/java/com/auraboot/module/aps/engine/SchedulingEngine.java

```java
@Service
@RequiredArgsConstructor
public class SchedulingEngine {
    private final Map<String, SchedulingStrategy> strategies; // Spring auto-injects by component name
    private final GanttDataBuilder ganttBuilder;

    public ScheduleResult schedule(ScheduleRequest request, String strategyName) {
        SchedulingStrategy strategy = strategies.get(strategyName);
        if (strategy == null) {
            throw new IllegalArgumentException("Unknown strategy: " + strategyName + ". Available: " + strategies.keySet());
        }
        return strategy.schedule(request);
    }

    public GanttData scheduleWithGantt(ScheduleRequest request, String strategyName) {
        ScheduleResult result = schedule(request, strategyName);
        return ganttBuilder.build(result);
    }

    public List<String> getAvailableStrategies() {
        return strategies.values().stream()
            .map(s -> s.name() + ": " + s.description())
            .collect(Collectors.toList());
    }
}
```

2. platform/src/main/java/com/auraboot/module/aps/controller/ApsController.java
```java
@RestController
@RequestMapping("/api/aps")
@RequiredArgsConstructor
public class ApsController {
    private final SchedulingEngine engine;

    @PostMapping("/schedule")
    public ResponseEntity<ScheduleResult> schedule(
            @RequestBody ApsScheduleRequest request) {
        ScheduleRequest schedReq = buildScheduleRequest(request);
        ScheduleResult result = engine.schedule(schedReq, request.getStrategy());
        return ResponseEntity.ok(result);
    }

    @PostMapping("/gantt")
    public ResponseEntity<GanttData> gantt(
            @RequestBody ApsScheduleRequest request) {
        ScheduleRequest schedReq = buildScheduleRequest(request);
        GanttData gantt = engine.scheduleWithGantt(schedReq, request.getStrategy());
        return ResponseEntity.ok(gantt);
    }

    @GetMapping("/strategies")
    public ResponseEntity<List<String>> strategies() {
        return ResponseEntity.ok(engine.getAvailableStrategies());
    }
}
```

